/**
 * Order validation — pure functions for validating order data.
 *
 * These validators contain no side effects and no database calls.
 * They can be reused across services and in tests.
 */

import type { OrderItem, OrderStatus } from '../models/order.js';

/**
 * Allowed status transitions for orders.
 */
export const VALID_STATUS_TRANSITIONS: Record<OrderStatus, OrderStatus[]> = {
  pending: ['confirmed', 'cancelled'],
  confirmed: ['shipped', 'cancelled'],
  shipped: ['delivered'],
  delivered: [],
  cancelled: [],
};

/**
 * Check whether a status transition is allowed.
 */
export function isValidStatusTransition(
  from: OrderStatus,
  to: OrderStatus,
): boolean {
  return VALID_STATUS_TRANSITIONS[from].includes(to);
}

/**
 * Validate that a status transition is allowed. Throws if not.
 */
export function validateStatusTransition(
  from: OrderStatus,
  to: OrderStatus,
): void {
  if (!isValidStatusTransition(from, to)) {
    throw new Error(`Invalid status transition: ${from} -> ${to}`);
  }
}

/**
 * Validate that an order has at least one item.
 */
export function validateOrderHasItems(items: OrderItem[]): void {
  if (items.length === 0) {
    throw new Error('Order must have at least one item');
  }
}

/**
 * User validation — pure functions for validating user data.
 *
 * These validators contain no side effects and no database calls.
 * They accept pre-fetched data and perform the validation logic.
 */

import type { User } from '../models/user.js';

/**
 * Validate that no user already exists with the given email (for creation).
 * Takes the result of a repository lookup as input.
 */
export function validateEmailNotTaken(
  existingUser: User | undefined,
  email: string,
): void {
  if (existingUser) {
    throw new Error(`User with email ${email} already exists`);
  }
}

/**
 * Validate that a user exists. Throws if not found.
 * Takes the result of a repository lookup as input.
 */
export function validateUserExists(
  user: User | undefined,
  id: string,
): asserts user is User {
  if (!user) {
    throw new Error(`User not found: ${id}`);
  }
}

/**
 * Validate that an email is available for update (not taken by another user).
 * Takes the result of a repository lookup as input.
 */
export function validateEmailAvailableForUpdate(
  existingUserWithEmail: User | undefined,
  email: string,
): void {
  if (existingUserWithEmail) {
    throw new Error(`Email ${email} is already in use`);
  }
}

