import { describe, it, expect } from 'vitest';
import {
  VALID_STATUS_TRANSITIONS,
  isValidStatusTransition,
  validateStatusTransition,
  validateOrderHasItems,
} from '../../src/validators/order.validator.js';
import type { OrderItem, OrderStatus } from '../../src/models/order.js';

describe('order.validator', () => {
  describe('VALID_STATUS_TRANSITIONS', () => {
    it('should allow pending → confirmed and cancelled', () => {
      expect(VALID_STATUS_TRANSITIONS.pending).toEqual(['confirmed', 'cancelled']);
    });

    it('should allow confirmed → shipped and cancelled', () => {
      expect(VALID_STATUS_TRANSITIONS.confirmed).toEqual(['shipped', 'cancelled']);
    });

    it('should allow shipped → delivered only', () => {
      expect(VALID_STATUS_TRANSITIONS.shipped).toEqual(['delivered']);
    });

    it('should not allow any transitions from delivered', () => {
      expect(VALID_STATUS_TRANSITIONS.delivered).toEqual([]);
    });

    it('should not allow any transitions from cancelled', () => {
      expect(VALID_STATUS_TRANSITIONS.cancelled).toEqual([]);
    });
  });

  describe('isValidStatusTransition', () => {
    it('should return true for valid transitions', () => {
      expect(isValidStatusTransition('pending', 'confirmed')).toBe(true);
      expect(isValidStatusTransition('pending', 'cancelled')).toBe(true);
      expect(isValidStatusTransition('confirmed', 'shipped')).toBe(true);
      expect(isValidStatusTransition('confirmed', 'cancelled')).toBe(true);
      expect(isValidStatusTransition('shipped', 'delivered')).toBe(true);
    });

    it('should return false for invalid transitions', () => {
      expect(isValidStatusTransition('pending', 'delivered')).toBe(false);
      expect(isValidStatusTransition('pending', 'shipped')).toBe(false);
      expect(isValidStatusTransition('shipped', 'cancelled')).toBe(false);
      expect(isValidStatusTransition('delivered', 'pending')).toBe(false);
      expect(isValidStatusTransition('cancelled', 'pending')).toBe(false);
    });

    it('should return false for same-status transitions', () => {
      const statuses: OrderStatus[] = ['pending', 'confirmed', 'shipped', 'delivered', 'cancelled'];
      for (const status of statuses) {
        expect(isValidStatusTransition(status, status)).toBe(false);
      }
    });
  });

  describe('validateStatusTransition', () => {
    it('should not throw for valid transitions', () => {
      expect(() => validateStatusTransition('pending', 'confirmed')).not.toThrow();
      expect(() => validateStatusTransition('confirmed', 'shipped')).not.toThrow();
      expect(() => validateStatusTransition('shipped', 'delivered')).not.toThrow();
    });

    it('should throw for invalid transitions', () => {
      expect(() => validateStatusTransition('pending', 'delivered')).toThrow(
        'Invalid status transition: pending -> delivered',
      );
    });

    it('should throw for transitions from terminal states', () => {
      expect(() => validateStatusTransition('delivered', 'confirmed')).toThrow(
        'Invalid status transition: delivered -> confirmed',
      );
      expect(() => validateStatusTransition('cancelled', 'confirmed')).toThrow(
        'Invalid status transition: cancelled -> confirmed',
      );
    });
  });

  describe('validateOrderHasItems', () => {
    it('should not throw for non-empty items', () => {
      const items: OrderItem[] = [
        { productId: 'p1', name: 'Widget', quantity: 1, unitPrice: 10 },
      ];
      expect(() => validateOrderHasItems(items)).not.toThrow();
    });

    it('should not throw for multiple items', () => {
      const items: OrderItem[] = [
        { productId: 'p1', name: 'Widget', quantity: 1, unitPrice: 10 },
        { productId: 'p2', name: 'Gadget', quantity: 2, unitPrice: 20 },
      ];
      expect(() => validateOrderHasItems(items)).not.toThrow();
    });

    it('should throw for empty items array', () => {
      expect(() => validateOrderHasItems([])).toThrow(
        'Order must have at least one item',
      );
    });
  });
});

import { describe, it, expect } from 'vitest';
import {
  validateEmailNotTaken,
  validateUserExists,
  validateEmailAvailableForUpdate,
} from '../../src/validators/user.validator.js';
import type { User } from '../../src/models/user.js';

const makeUser = (overrides?: Partial<User>): User => ({
  id: 'user-0001',
  name: 'Alice',
  email: 'alice@example.com',
  role: 'member',
  createdAt: new Date(),
  updatedAt: new Date(),
  ...overrides,
});

describe('user.validator', () => {
  describe('validateEmailNotTaken', () => {
    it('should not throw when no existing user found', () => {
      expect(() => validateEmailNotTaken(undefined, 'new@example.com')).not.toThrow();
    });

    it('should throw when a user with the email exists', () => {
      const existing = makeUser({ email: 'taken@example.com' });
      expect(() => validateEmailNotTaken(existing, 'taken@example.com')).toThrow(
        'User with email taken@example.com already exists',
      );
    });
  });

  describe('validateUserExists', () => {
    it('should not throw when user is defined', () => {
      const user = makeUser();
      expect(() => validateUserExists(user, 'user-0001')).not.toThrow();
    });

    it('should throw when user is undefined', () => {
      expect(() => validateUserExists(undefined, 'user-9999')).toThrow(
        'User not found: user-9999',
      );
    });

    it('should act as type assertion (asserts user is User)', () => {
      const user: User | undefined = makeUser();
      validateUserExists(user, 'user-0001');
      // After validation, TypeScript should narrow the type
      expect(user.name).toBe('Alice');
    });
  });

  describe('validateEmailAvailableForUpdate', () => {
    it('should not throw when no user has the email', () => {
      expect(() => validateEmailAvailableForUpdate(undefined, 'free@example.com')).not.toThrow();
    });

    it('should throw when email is taken by another user', () => {
      const other = makeUser({ id: 'user-0002', email: 'taken@example.com' });
      expect(() => validateEmailAvailableForUpdate(other, 'taken@example.com')).toThrow(
        'Email taken@example.com is already in use',
      );
    });
  });
});

